-- §3d wac-title category — INTENTIONALLY EMPTY at apply (lazy-populated Phase 4)


-- =============================================================================
-- §POST-APPLY GUARDS
-- =============================================================================

DO $$
DECLARE
  tables_count             INTEGER;
  cj_count                 INTEGER;
  wac_meta_count           INTEGER;
  wac_title_count          INTEGER;
  topical_count            INTEGER;
  total_legal_framework    INTEGER;
  rcw_section_count        INTEGER;
  usc_tag_count            INTEGER;
  rcw_tag_count            INTEGER;
  wac_tag_count            INTEGER;
  chk_count                INTEGER;
  rcw_check_def            TEXT;
  wac_check_def            TEXT;
BEGIN
  -- §POST.1 All 8 wac.* tables exist
  SELECT COUNT(*) INTO tables_count FROM information_schema.tables
    WHERE table_schema='wac'
      AND table_name IN (
        'titles','chapters','sections','cross_references',
        'section_history','section_notes','ingestion_runs','authority_chain'
      );
  IF tables_count <> 8 THEN
    RAISE EXCEPTION 'Post-apply FAIL: wac schema has % expected tables, got %.', 8, tables_count;
  END IF;

  -- §POST.2 code-jurisdiction now has 3 rows (federal-usc, state-wa-rcw, state-wa-wac)
  SELECT COUNT(*) INTO cj_count FROM core.tags WHERE category='code-jurisdiction';
  IF cj_count <> 3 THEN
    RAISE EXCEPTION 'Post-apply FAIL: code-jurisdiction has % rows, expected 3.', cj_count;
  END IF;

  -- §POST.3 wac-meta has 8 rows
  SELECT COUNT(*) INTO wac_meta_count FROM core.tags WHERE category='wac-meta';
  IF wac_meta_count <> 8 THEN
    RAISE EXCEPTION 'Post-apply FAIL: wac-meta has % rows, expected 8.', wac_meta_count;
  END IF;

  -- §POST.4 wac-title intentionally still empty (lazy-populated)
  SELECT COUNT(*) INTO wac_title_count FROM core.tags WHERE category='wac-title';
  IF wac_title_count <> 0 THEN
    RAISE EXCEPTION 'Post-apply FAIL: wac-title has % rows, expected 0 (lazy-populated).', wac_title_count;
  END IF;

  -- §POST.5 11 new legal-framework topical tags inserted
  SELECT COUNT(*) INTO topical_count FROM core.tags WHERE category='legal-framework' AND slug LIKE '%-wac';
  IF topical_count <> 11 THEN
    RAISE EXCEPTION 'Post-apply FAIL: %-wac topical tag count is %, expected 11.', topical_count, 11;
  END IF;
  SELECT COUNT(*) INTO total_legal_framework FROM core.tags WHERE category='legal-framework';
  -- Total legal-framework = (28 federal from USC Phase 1) + (17 RCW from RCW Phase 1) + (11 WAC) = 56
  IF total_legal_framework <> 56 THEN
    RAISE EXCEPTION 'Post-apply FAIL: total legal-framework is %, expected 56 (28+17+11).', total_legal_framework;
  END IF;

  -- §POST.6 RCW + USC corpora unchanged
  SELECT COUNT(*) INTO rcw_section_count FROM rcw.sections;
  IF rcw_section_count <> 51764 THEN
    RAISE EXCEPTION 'Post-apply FAIL: rcw.sections changed from 51,764 to %.', rcw_section_count;
  END IF;
  SELECT COUNT(*) INTO usc_tag_count FROM core.document_tags dt
    JOIN core.tags t ON t.id=dt.tag_id
    WHERE t.category='code-jurisdiction' AND t.slug='federal-usc';
  IF usc_tag_count <> 11678 THEN
    RAISE EXCEPTION 'Post-apply FAIL: USC code-jurisdiction tag count changed from 11,678 to %.', usc_tag_count;
  END IF;
  SELECT COUNT(*) INTO rcw_tag_count FROM core.document_tags dt
    JOIN core.tags t ON t.id=dt.tag_id
    WHERE t.category='code-jurisdiction' AND t.slug='state-wa-rcw';
  IF rcw_tag_count <> 51764 THEN
    RAISE EXCEPTION 'Post-apply FAIL: RCW code-jurisdiction tag count changed from 51,764 to %.', rcw_tag_count;
  END IF;

  -- §POST.7 No documents tagged with state-wa-wac yet (Phase 4 will populate)
  SELECT COUNT(*) INTO wac_tag_count FROM core.document_tags dt
    JOIN core.tags t ON t.id=dt.tag_id
    WHERE t.category='code-jurisdiction' AND t.slug='state-wa-wac';
  IF wac_tag_count <> 0 THEN
    RAISE EXCEPTION 'Post-apply FAIL: state-wa-wac has % doc-tag associations, expected 0 pre-Phase-4.', wac_tag_count;
  END IF;

  -- §POST.8 Critical CHECK constraints registered
  SELECT COUNT(*) INTO chk_count FROM pg_constraint
    WHERE conname IN (
      'chk_section_text_status_invariant','chk_recodified_target',
      'chk_pending_recodification_pair','chk_unit_type','chk_authority_xor'
    )
    AND conrelid IN ('wac.sections'::regclass, 'wac.authority_chain'::regclass);
  IF chk_count <> 5 THEN
    RAISE EXCEPTION 'Post-apply FAIL: % of expected 5 CHECK constraints registered.', chk_count;
  END IF;

  -- §POST.9 Harmonized CHECK enums on BOTH cross-references tables include
  --         'state-wa-wac' and DO NOT include 'wac' short form.
  SELECT pg_get_constraintdef(oid) INTO rcw_check_def FROM pg_constraint
    WHERE conname='chk_target_jurisdiction' AND conrelid='rcw.cross_references'::regclass;
  IF rcw_check_def NOT LIKE '%state-wa-wac%' THEN
    RAISE EXCEPTION 'Post-apply FAIL: rcw.cross_references CHECK does not include ''state-wa-wac''. Got: %', rcw_check_def;
  END IF;
  IF rcw_check_def LIKE '%''wac''%' THEN
    RAISE EXCEPTION 'Post-apply FAIL: rcw.cross_references CHECK still includes short-form ''wac''. Got: %', rcw_check_def;
  END IF;
  SELECT pg_get_constraintdef(oid) INTO wac_check_def FROM pg_constraint
    WHERE conname='chk_target_jurisdiction' AND conrelid='wac.cross_references'::regclass;
  IF wac_check_def NOT LIKE '%state-wa-wac%' THEN
    RAISE EXCEPTION 'Post-apply FAIL: wac.cross_references CHECK does not include ''state-wa-wac''. Got: %', wac_check_def;
  END IF;
  IF wac_check_def LIKE '%''wac''%' THEN
    RAISE EXCEPTION 'Post-apply FAIL: wac.cross_references CHECK still includes short-form ''wac''. Got: %', wac_check_def;
  END IF;

  RAISE NOTICE 'Post-apply guards: PASS (8 wac tables; 3 code-juris; 8 wac-meta; 0 wac-title; 11 wac topical; 5 CHECKs; RCW/USC unchanged; both cross_refs CHECKs harmonized to state-wa-wac)';
END $$;


-- =============================================================================
-- COMMIT
-- =============================================================================

COMMIT;


-- =============================================================================
-- §VERIFICATION SELECTs (post-commit, for operator review)
-- =============================================================================

\echo ''
\echo '--- §V.1 wac schema and 8 tables ---'
SELECT
  EXISTS (SELECT 1 FROM information_schema.schemata WHERE schema_name='wac')                                               AS wac_schema,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='wac' AND table_name='titles')           AS titles_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='wac' AND table_name='chapters')         AS chapters_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='wac' AND table_name='sections')         AS sections_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='wac' AND table_name='cross_references') AS xref_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='wac' AND table_name='section_history')  AS history_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='wac' AND table_name='section_notes')    AS notes_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='wac' AND table_name='ingestion_runs')   AS runs_tbl,
  EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='wac' AND table_name='authority_chain')  AS authority_tbl;

\echo ''
\echo '--- §V.2 Tag categories (expect 3 / 8 / 0 / 56) ---'
SELECT
  (SELECT COUNT(*) FROM core.tags WHERE category='code-jurisdiction')   AS code_jurisdiction_n,
  (SELECT COUNT(*) FROM core.tags WHERE category='wac-meta')            AS wac_meta_n,
  (SELECT COUNT(*) FROM core.tags WHERE category='wac-title')           AS wac_title_n,
  (SELECT COUNT(*) FROM core.tags WHERE category='legal-framework')     AS legal_framework_total;

\echo ''
\echo '--- §V.3 RCW + USC corpora unchanged (51,764 + 11,678) ---'
SELECT
  (SELECT COUNT(*) FROM rcw.sections)                                                                       AS rcw_sections,
  (SELECT COUNT(*) FROM core.document_tags dt JOIN core.tags t ON t.id=dt.tag_id WHERE t.slug='federal-usc')  AS usc_tag_count,
  (SELECT COUNT(*) FROM core.document_tags dt JOIN core.tags t ON t.id=dt.tag_id WHERE t.slug='state-wa-rcw') AS rcw_tag_count,
  (SELECT COUNT(*) FROM core.document_tags dt JOIN core.tags t ON t.id=dt.tag_id WHERE t.slug='state-wa-wac') AS wac_tag_count;  -- expect 0

\echo ''
\echo '--- §V.4 CHECK constraints (5 critical) ---'
SELECT conname, conrelid::regclass::text AS table_name FROM pg_constraint
WHERE conname IN (
  'chk_section_text_status_invariant','chk_recodified_target',
  'chk_pending_recodification_pair','chk_unit_type','chk_authority_xor'
)
AND conrelid IN ('wac.sections'::regclass, 'wac.authority_chain'::regclass)
ORDER BY conname;

\echo ''
\echo '--- §V.5 New legal-framework WAC topical tags (expect 11) ---'
SELECT slug FROM core.tags WHERE category='legal-framework' AND slug LIKE '%-wac' ORDER BY slug;

\echo ''
\echo '--- §V.6 Harmonized cross-references CHECK enums (both tables; both contain state-wa-wac, neither contains short ''wac'') ---'
SELECT
  conrelid::regclass::text AS table_name,
  pg_get_constraintdef(oid) AS check_def
FROM pg_constraint
WHERE conname='chk_target_jurisdiction'
  AND conrelid IN ('rcw.cross_references'::regclass, 'wac.cross_references'::regclass)
ORDER BY table_name;

\echo ''
\echo '=== END schema_apply.sql ==='
